INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('dipole_growth_timer_desync', 'Dipole-engine one-shot growth stamps (p-vector draw-in / field switch-on) are ABSOLUTE time stamps invisible to RESET_TRAJECTORY, so THE EYE''s dense-series capture (which rebases stateStartTime AFTER the primary reveal-target capture has already snapped time forward) reads every dense frame as already-grown from t=0', 'MAJOR', 'peter_parker:renderer_primitives', 'FIXED 2026-07-08. applyDipoleInFieldState() stamped lg.userData.pGrowStartTime / .fieldGrowStartTime as `time` (absolute, at state entry). The p-arrow / field-fade ramps then read (time - stamp)/duration. THE EYE''s primary/frozen capture SNAPS `time` forward to the reveal-target ms for accumulator-free scenario types (incl. pe_external_field, gated in the animate() loop). It then sends RESET_TRAJECTORY before the dense series, which rebases ONLY stateStartTime (never these per-object stamps) -- so the dense series'' own t=0 landed on a clock already ~2.4s past the stale stamp, and since the growth ramp saturates at 1 after 0.9s, every dense frame (t=0..15000ms) read as already-grown (STATE_5''s p-arrow: 16/16 frames pixel-identical). CONFIRMED capture-harness-only via reading the real SET_STATE/postMessage path (build_review_site.ts): production never snaps time forward past where growth naturally reached -- it only crawls or holds at the current position -- so real students never saw a dead already-grown dipole.', 'Any one-shot reveal/growth timer in field_3d_renderer.ts (the dipole engine or any future scenario) must be a pure function of (time - stateStartTime), NEVER a separately-stamped absolute `time` value UNLESS that stamp has a genuine mid-state re-trigger caller (e.g. physics_release) that stateStartTime cannot represent. RESET_TRAJECTORY only ever rebases stateStartTime -- any timer that does not derive from it will desync the moment a primary/frozen capture (or any future forward time-snap) advances the clock before the timer''s own reveal window is captured.', 'js_eval', 'For a concept using p_animate_in or e_field_animate_in (grep src/data/concepts for these keys; applyDipoleInFieldState consumers), run visual:eyes with --dense and read the dense frame series for the state that declares the flag: the growth/fade must show visible progression between t=0 and its declared duration (e.g. p-arrow: near-zero length at t=0, full length by ~t=1000ms), NOT already-final at t=0. A state where ALL dense frames are pixel-identical AND the state declares a *_animate_in flag is this bug class.', 'FIXED', ARRAY['potential_energy_in_external_field', 'electric_dipole_in_field', 'bar_magnet_in_uniform_field'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-07-08_pe_external_field_state5_growth_timer_desync', 'incident')
